import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { API, showError, showSuccess } from '../../helpers';
import { Button } from '../../components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from '../../components/ui/dialog';
import { Check, ArrowRight, Rocket } from 'lucide-react';

const SubscriptionPage = () => {
  const { t } = useTranslation();
  const [subscription, setSubscription] = useState(null);
  const [currentPlan, setCurrentPlan] = useState(null);
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [dialogAction, setDialogAction] = useState(null);
  const [selectedPlan, setSelectedPlan] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [subRes, planRes] = await Promise.all([
        API.get('/api/subscription/self'),
        API.get('/api/plan/'),
      ]);

      if (subRes.data.success && subRes.data.data) {
        setSubscription(subRes.data.data.subscription);
        setCurrentPlan(subRes.data.data.plan);
      }
      if (planRes.data.success) {
        setPlans(planRes.data.data || []);
      }
    } catch (err) {
      showError(t('console.subscription.load_failed'));
    }
    setLoading(false);
  };

  const handleSelectPlan = (plan) => {
    setSelectedPlan(plan);
    if (!subscription) {
      setDialogAction('subscribe');
    } else if (plan.priority > (currentPlan?.priority || 0)) {
      setDialogAction('upgrade');
    } else {
      setDialogAction('downgrade');
    }
    setDialogOpen(true);
  };

  const handleConfirmAction = async () => {
    if (!selectedPlan) return;
    setActionLoading(true);
    try {
      let res;
      if (dialogAction === 'subscribe') {
        res = await API.post('/api/subscription/', { plan_id: selectedPlan.id });
      } else if (dialogAction === 'upgrade') {
        res = await API.put('/api/subscription/upgrade', { plan_id: selectedPlan.id });
      } else if (dialogAction === 'downgrade') {
        res = await API.put('/api/subscription/downgrade', { plan_id: selectedPlan.id });
      }

      if (res.data.success) {
        showSuccess(res.data.message || t('console.subscription.operation_success'));
        setDialogOpen(false);
        loadData();
      } else {
        showError(res.data.message);
      }
    } catch (err) {
      showError(t('console.subscription.operation_failed'));
    }
    setActionLoading(false);
  };

  // Format expiry date
  const getExpiryDate = () => {
    if (!subscription?.current_period_end) return '';
    const date = new Date(subscription.current_period_end * 1000);
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
  };

  // Get features list for a plan
  const getPlanFeatures = (plan) => {
    const features = [];
    if (plan.window_limit_count && plan.window_duration_sec) {
      features.push(`${plan.window_limit_count} 次/${Math.floor(plan.window_duration_sec / 3600)}h 频限`);
    }
    if (plan.weekly_limit_count > 0) {
      features.push(`周限额 ${plan.weekly_limit_count} 次`);
    }
    if (plan.overage_rate_type === 'api') {
      features.push('超额按量付费');
    } else {
      features.push('超额后暂停服务');
    }
    return features;
  };

  // Determine plan tier name styling (Figma uses JetBrains Mono Medium 28px)
  const getPlanPrice = (plan) => {
    if (plan.price_cents_monthly === 0) return 'Free';
    return `¥${(plan.price_cents_monthly / 100).toFixed(0)}`;
  };

  // Check if a plan is recommended (highest priority non-enterprise plan)
  const isRecommended = (plan) => {
    const nonEnterprise = plans.filter((p) => p.price_cents_monthly > 0 && p.price_cents_monthly < 100000);
    if (nonEnterprise.length === 0) return false;
    const maxPriority = Math.max(...nonEnterprise.map((p) => p.priority));
    return plan.priority === maxPriority;
  };

  if (loading) {
    return (
      <div className='flex items-center justify-center py-20 text-[#9eacbf]'>
        加载中...
      </div>
    );
  }

  return (
    <div className='flex flex-col min-h-0'>
      {/* Page header */}
      <div className='bg-white px-6 py-5 border-b border-[#e1e7ef]'>
        <h1 className='text-2xl font-medium text-[#090e1a] leading-8'>套餐</h1>
        <p className='text-base text-[#65758b] mt-1'>从免费试用开始，按需升级</p>
      </div>

      {/* Content */}
      <div className='flex-1 overflow-y-auto p-6 space-y-6'>
        {/* Current plan banner */}
        {currentPlan && (
          <div className='bg-[#f0f5ff] border border-[#bdceff] px-6 py-5 flex items-center justify-between'>
            <div className='flex items-center gap-4'>
              <span className='inline-flex items-center h-6 px-2 text-xs font-medium bg-white border border-[#bdceff] text-[#4362ff]'>
                当前套餐
              </span>
              <span className='text-xl font-medium text-[#090e1a] font-mono'>
                {currentPlan.display_name || currentPlan.name}
              </span>
              {subscription?.current_period_end && (
                <span className='text-sm text-[#65758b]'>
                  有效期至 {getExpiryDate()}
                </span>
              )}
            </div>
            <Link
              to='/billing'
              className='inline-flex items-center gap-1 text-sm text-[#4362ff] hover:underline no-underline font-medium'
            >
              管理订阅
              <ArrowRight className='h-4 w-4' />
            </Link>
          </div>
        )}

        {/* Plan cards */}
        <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4'>
          {plans.map((plan) => {
            const isCurrent = plan.id === currentPlan?.id;
            const recommended = isRecommended(plan);
            const features = getPlanFeatures(plan);
            const isUpgrade = currentPlan && plan.priority > (currentPlan.priority || 0);
            const isDowngrade = currentPlan && plan.priority < (currentPlan.priority || 0);

            return (
              <div
                key={plan.id}
                className={`relative bg-white border ${
                  isCurrent ? 'border-[#4362ff]' : 'border-[#e1e7ef]'
                } flex flex-col`}
                style={{ minWidth: 0 }}
              >
                {/* Recommended badge */}
                {recommended && !isCurrent && (
                  <div className='absolute -top-3 left-1/2 -translate-x-1/2 z-10'>
                    <span className='inline-flex items-center h-6 px-3 text-xs font-medium bg-[#4362ff] text-white'>
                      推荐
                    </span>
                  </div>
                )}

                <div className='p-6 flex flex-col flex-1'>
                  {/* Plan name */}
                  <h3 className='text-2xl font-medium text-[#090e1a] font-mono'>
                    {plan.display_name || plan.name}
                  </h3>
                  {plan.description && (
                    <p className='text-sm text-[#65758b] mt-1'>{plan.description}</p>
                  )}

                  {/* Price */}
                  <div className='mt-4 mb-5'>
                    <span className='text-4xl font-bold text-[#090e1a]' style={{ fontFamily: "'D-DIN', 'JetBrains Mono', monospace" }}>
                      {getPlanPrice(plan)}
                    </span>
                    {plan.price_cents_monthly > 0 && (
                      <span className='text-sm text-[#9eacbf] ml-1'>/月</span>
                    )}
                  </div>

                  {/* Features */}
                  <ul className='space-y-3 flex-1'>
                    {features.map((feature, i) => (
                      <li key={i} className='flex items-start gap-2'>
                        <div className='w-4 h-4 bg-[#f0f5ff] flex items-center justify-center flex-shrink-0 mt-0.5'>
                          <Check className='h-3 w-3 text-[#4362ff]' />
                        </div>
                        <span className='text-sm text-[#344256]'>{feature}</span>
                      </li>
                    ))}
                  </ul>

                  {/* CTA button */}
                  <div className='mt-6'>
                    {isCurrent ? (
                      <button
                        className='w-full h-10 border border-[#e1e7ef] bg-[#f8fafc] text-[#9eacbf] text-sm font-medium cursor-default'
                        disabled
                      >
                        当前套餐
                      </button>
                    ) : plan.price_cents_monthly === 0 ? (
                      <button
                        className='w-full h-10 border border-[#e1e7ef] bg-white text-[#344256] text-sm font-medium hover:bg-[#f8fafc] transition-colors cursor-pointer'
                        onClick={() => handleSelectPlan(plan)}
                      >
                        开始使用
                      </button>
                    ) : recommended ? (
                      <button
                        className='w-full h-10 bg-[#4362ff] hover:bg-[#3451e6] text-white text-sm font-medium transition-colors cursor-pointer border-0'
                        onClick={() => handleSelectPlan(plan)}
                      >
                        {isUpgrade ? '升级到此套餐' : isDowngrade ? '降级到此套餐' : '选择此套餐'}
                      </button>
                    ) : (
                      <button
                        className='w-full h-10 border border-[#4362ff] bg-white text-[#4362ff] text-sm font-medium hover:bg-[#f0f5ff] transition-colors cursor-pointer'
                        onClick={() => handleSelectPlan(plan)}
                      >
                        {isUpgrade ? '升级到此套餐' : isDowngrade ? '降级到此套餐' : '选择此套餐'}
                      </button>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Booster CTA banner */}
        <div
          className='px-8 py-6 flex items-center justify-between'
          style={{
            background: 'linear-gradient(135deg, #4362ff 0%, #5b7cff 50%, #7b9aff 100%)',
          }}
        >
          <div className='flex items-center gap-4'>
            <div className='w-10 h-10 bg-white/20 flex items-center justify-center'>
              <Rocket className='h-5 w-5 text-white' />
            </div>
            <div>
              <h3 className='text-lg font-medium text-white'>需要更多额度？</h3>
              <p className='text-sm text-white/70 mt-0.5'>购买加油包，灵活补充调用次数，有效期30天</p>
            </div>
          </div>
          <Link to='/booster'>
            <button className='h-10 px-6 bg-white text-[#4362ff] text-sm font-medium hover:bg-white/90 transition-colors cursor-pointer border-0'>
              购买加油包
            </button>
          </Link>
        </div>
      </div>

      {/* Confirm dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {dialogAction === 'subscribe' && '确认订阅'}
              {dialogAction === 'upgrade' && '确认升级'}
              {dialogAction === 'downgrade' && '确认降级'}
            </DialogTitle>
            <DialogDescription>
              {dialogAction === 'subscribe' && (
                <>确认订阅 <strong>{selectedPlan?.display_name}</strong> 套餐？</>
              )}
              {dialogAction === 'upgrade' && (
                <>确认从 <strong>{currentPlan?.display_name}</strong> 升级到 <strong>{selectedPlan?.display_name}</strong>？</>
              )}
              {dialogAction === 'downgrade' && (
                <>确认从 <strong>{currentPlan?.display_name}</strong> 降级到 <strong>{selectedPlan?.display_name}</strong>？降级将在当前计费周期结束后生效。</>
              )}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant='outline' onClick={() => setDialogOpen(false)}>
              取消
            </Button>
            <Button
              className='bg-[#4362ff] hover:bg-[#3451e6] text-white'
              onClick={handleConfirmAction}
              disabled={actionLoading}
            >
              {actionLoading ? '处理中...' : '确认'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default SubscriptionPage;
